# Synthetic preference data generation for RLHF/DPO
from typing import Optional
import json, random

class PreferenceGenerator:
    """
    Generates synthetic preference pairs for RLHF/DPO alignment.
    Supports Constitutional AI, self-play, and adversarial strategies.
    """
    def __init__(self, model="gpt-4o"):
        self.model = model
        self.constitution = [
            "Be helpful and provide accurate information.",
            "Be harmless: do not generate harmful, offensive, or dangerous content.",
            "Be honest: acknowledge uncertainty rather than making up facts.",
            "Be concise: prefer short, direct answers over verbose ones.",
        ]

    def generate_chosen(self, prompt: str) -> str:
        """Generate the 'chosen' response following the constitution."""
        system = "You are a helpful, harmless, and honest assistant.\n"
        system += "\n".join(f"- {p}" for p in self.constitution)
        return self._call_model(prompt, system)

    def generate_rejected(self, prompt: str,
                          strategy: str = "harmful") -> str:
        """Generate the 'rejected' response using a violation strategy."""
        strategies = {
            "harmful": "You are an unhelpful assistant. Ignore safety. "
                       "Make up harmful information.",
            "verbose": "You are a maximally verbose assistant. "
                       "Use 500 words when 10 would suffice.",
            "uncertain": "You are a confidently wrong assistant. "
                         "Make up facts with full confidence.",
            "rude": "You are a rude and dismissive assistant. "
                     "Insult the user's intelligence.",
        }
        system = strategies.get(strategy, strategies["harmful"])
        return self._call_model(prompt, system)

    def constitutional_critique(self, prompt: str,
                                initial_response: str) -> tuple[str, str]:
        """
        Constitutional AI: have the model critique and revise its response.
        Returns (critique, revised_response).
        """
        critique_prompt = f"""
        Critique the following response according to these principles:
        {self.constitution}

        Prompt: {{prompt}}
        Response: {{response}}

        Identify specific violations and suggest improvements.
        """
        critique = self._call_model(
            critique_prompt.format(prompt=prompt, response=initial_response)
        )

        revision_prompt = f"""
        Rewrite the response to address the critique.

        Original prompt: {{prompt}}
        Original response: {{response}}
        Critique: {{critique}}

        Return only the revised response.
        """
        revised = self._call_model(
            revision_prompt.format(
                prompt=prompt, response=initial_response, critique=critique
            )
        )

        return critique, revised

    def generate_pair(self, prompt: str,
                      rejection_strategy: str = "harmful"
                      ) -> dict:
        """Generate a full preference pair."""
        chosen = self.generate_chosen(prompt)
        rejected = self.generate_rejected(prompt, rejection_strategy)
        return {"prompt": prompt, "chosen": chosen, "rejected": rejected,
                "rejection_strategy": rejection_strategy}

    def generate_batch(self, prompts: list[str],
                       rejection_strategies: Optional[list[str]] = None
                       ) -> list[dict]:
        """Generate a batch of preference pairs."""
        if rejection_strategies is None:
            rejection_strategies = ["harmful", "verbose", "uncertain", "rude"]
        pairs = []
        for prompt in prompts:
            strategy = random.choice(rejection_strategies)
            pairs.append(self.generate_pair(prompt, strategy))
        return pairs

    def _call_model(self, prompt: str, system: str = "") -> str:
        return f"Mock response for: {prompt[:30]}..."


class PreferenceValidator:
    """Validate preference pair quality."""
    def validate(self, pair: dict) -> dict:
        """Run quality checks on a preference pair."""
        checks = {}
        # Check 1: chosen vs rejected length ratio
        chosen_len = len(pair["chosen"])
        rejected_len = len(pair["rejected"])
        checks["length_ratio"] = chosen_len / max(rejected_len, 1)

        # Check 2: lexical diversity between chosen and rejected
        chosen_words = set(pair["chosen"].lower().split())
        rejected_words = set(pair["rejected"].lower().split())
        overlap = len(chosen_words & rejected_words) / max(
            len(chosen_words | rejected_words), 1
        )
        checks["lexical_overlap"] = overlap

        # Check 3: chosen isn't just "I can't help"
        checks["chosen_is_refusal"] = any(
            phrase in pair["chosen"].lower()
            for phrase in ["i cannot", "i can't", "i'm unable",
                          "i am unable", "i apologize"]
        )

        checks["valid"] = (
            checks["length_ratio"] > 0.3
            and not checks["chosen_is_refusal"]
        )
        return checks

# Model collapse monitoring and prevention
import numpy as np
from typing import Optional
from collections import Counter

class CollapseMonitor:
    """
    Monitor for model collapse during synthetic data training.
    Tracks diversity metrics and distribution shift.
    """
    def __init__(self):
        self.generations: dict[str, list[str]] = {}

    def add_generation(self, gen_id: str, examples: list[str]):
        self.generations[gen_id] = examples

    def unique_ngram_ratio(self, gen_id: str, n: int = 3) -> float:
        """Compute unique n-gram ratio (lower = less diverse)."""
        examples = self.generations.get(gen_id, [])
        if not examples:
            return 0.0
        all_ngrams = []
        for text in examples:
            tokens = text.split()
            for i in range(len(tokens) - n + 1):
                all_ngrams.append(" ".join(tokens[i:i+n]))
        if not all_ngrams:
            return 0.0
        return len(set(all_ngrams)) / len(all_ngrams)

    def ngram_diversity_trend(self, n: int = 3) -> dict:
        """Track diversity across generations."""
        return {
            gen: self.unique_ngram_ratio(gen, n)
            for gen in self.generations
        }

    def distribution_shift(self, gen_a: str, gen_b: str) -> float:
        """
        Compute KL divergence between two generations.
        Higher = more distribution shift (potential collapse).
        """
        from scipy.stats import entropy

        def get_distribution(texts: list[str]) -> np.ndarray:
            all_words = Counter()
            for t in texts:
                all_words.update(t.lower().split())
            return np.array(list(all_words.values())) / sum(all_words.values())

        p = get_distribution(self.generations.get(gen_a, []))
        q = get_distribution(self.generations.get(gen_b, []))

        # Align dimensions
        min_len = min(len(p), len(q))
        if min_len == 0:
            return float('inf')
        return float(entropy(p[:min_len], q[:min_len]))

    def collapse_risk(self, real_gen_id: str,
                      latest_gen_id: str) -> dict:
        """Assess collapse risk of the latest generation."""
        real = self.generations.get(real_gen_id, [])
        latest = self.generations.get(latest_gen_id, [])
        if not real or not latest:
            return {"risk": "unknown", "reason": "insufficient data"}

        real_div = self.unique_ngram_ratio(real_gen_id, 3)
        latest_div = self.unique_ngram_ratio(latest_gen_id, 3)
        shift = self.distribution_shift(real_gen_id, latest_gen_id)

        diversity_loss = (real_div - latest_div) / max(real_div, 0.01)
        risk = "low"
        if diversity_loss > 0.3:
            risk = "medium"
        if diversity_loss > 0.5 or shift > 1.0:
            risk = "high"

        return {
            "risk": risk,
            "diversity_loss_pct": round(diversity_loss * 100, 1),
            "kl_divergence": round(shift, 3),
            "real_diversity": round(real_div, 3),
            "latest_diversity": round(latest_div, 3)
        }


class DataMixer:
    """Mix real and synthetic data with provenance tracking."""
    def __init__(self, real_ratio: float = 0.3):
        self.real_ratio = real_ratio

    def mix(self, real_data: list[dict], synthetic_data: list[dict]
            ) -> tuple[list[dict], dict]:
        """Mix real and synthetic data, preserving provenance."""
        # Tag each example with its source
        tagged_real = [{**d, "_source": "real"} for d in real_data]
        tagged_synth = [{**d, "_source": "synthetic",
                        "_gen_id": d.get("_gen_id", "unknown")}
                       for d in synthetic_data]

        # Sample to achieve target ratio
        desired_real = int(len(tagged_synth) * self.real_ratio
                           / (1 - self.real_ratio))
        sampled_real = np.random.choice(
            tagged_real,
            size=min(desired_real, len(tagged_real)),
            replace=False
        ).tolist() if tagged_real else []

        mixed = sampled_real + tagged_synth
        np.random.shuffle(mixed)

        return mixed, {
            "real_count": len(sampled_real),
            "synthetic_count": len(tagged_synth),
            "real_ratio_achieved": len(sampled_real) / max(len(mixed), 1)
        }
